function automatic integer gate_depth;
  input integer way;
  integer d1, d2, sc, n1, n2;
  begin
    if (way <= 1) gate_depth = 0;
    else if (way <= 4) gate_depth = 1;
    else begin
      sc = $clog2(way);
      n1 = 1 << (sc - 1);
      n2 = way - n1;
      d1 = gate_depth(n1);
      d2 = gate_depth(n2);
      gate_depth = ((d1 > d2) ? d1 : d2) + 1;
    end
  end
endfunction

function automatic integer gate_depth;
  input integer way;
  begin
    if (way <= 1) gate_depth = 0;
    else gate_depth = 1 + gate_depth(way / 2);
  end
endfunction

module t;
  localparam D = gate_depth(8);
endmodule
